const listRelatedCategoriesByFunction = `-- name: ListRelatedCategoriesByFunction :many
SELECT categorized_job_title, COUNT(id)::bigint AS score
FROM parsed_jobs
WHERE categorized_job_title IS NOT NULL
  AND categorized_job_title != ''
  AND categorized_job_function = $1
GROUP BY categorized_job_title
ORDER BY CASE WHEN categorized_job_title = $2 THEN 0 ELSE 1 END ASC,
         score DESC,
         categorized_job_title ASC
LIMIT $3
`

type ListRelatedCategoriesByFunctionParams struct {
	CategorizedJobFunction pgtype.Text `json:"categorized_job_function"`
	CategorizedJobTitle    pgtype.Text `json:"categorized_job_title"`
	Limit                  int32       `json:"limit"`
}

type ListRelatedCategoriesByFunctionRow struct {
	CategorizedJobTitle pgtype.Text `json:"categorized_job_title"`
	Score               int64       `json:"score"`
}

func (q *Queries) ListRelatedCategoriesByFunction(ctx context.Context, arg ListRelatedCategoriesByFunctionParams) ([]*ListRelatedCategoriesByFunctionRow, error) {
	rows, err := q.db.Query(ctx, listRelatedCategoriesByFunction, arg.CategorizedJobFunction, arg.CategorizedJobTitle, arg.Limit)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []*ListRelatedCategoriesByFunctionRow
	for rows.Next() {
		var i ListRelatedCategoriesByFunctionRow
		if err := rows.Scan(&i.CategorizedJobTitle, &i.Score); err != nil {
			return nil, err
		}
		items = append(items, &i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

const listTopCategories = `-- name: ListTopCategories :many
SELECT categorized_job_title, COUNT(id)::bigint AS score
FROM parsed_jobs
WHERE categorized_job_title IS NOT NULL
  AND categorized_job_title != ''
  AND created_at_source IS NOT NULL
  AND created_at_source >= $1
  AND (
    NOT $2::boolean
    OR CAST(location_us_states AS text) ILIKE $3
    OR CAST(location_countries AS text) ILIKE $4
  )
GROUP BY categorized_job_title
ORDER BY score DESC, categorized_job_title ASC
LIMIT $5
`

type ListTopCategoriesParams struct {
	CreatedAtSource   pgtype.Timestamptz `json:"created_at_source"`
	Column2           bool               `json:"column_2"`
	LocationUsStates  []byte             `json:"location_us_states"`
	LocationCountries []byte             `json:"location_countries"`
	Limit             int32              `json:"limit"`
}

type ListTopCategoriesRow struct {
	CategorizedJobTitle pgtype.Text `json:"categorized_job_title"`
	Score               int64       `json:"score"`
}

func (q *Queries) ListTopCategories(ctx context.Context, arg ListTopCategoriesParams) ([]*ListTopCategoriesRow, error) {
	rows, err := q.db.Query(ctx, listTopCategories,
		arg.CreatedAtSource,
		arg.Column2,
		arg.LocationUsStates,
		arg.LocationCountries,
		arg.Limit,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []*ListTopCategoriesRow
	for rows.Next() {
		var i ListTopCategoriesRow
		if err := rows.Scan(&i.CategorizedJobTitle, &i.Score); err != nil {
			return nil, err
		}
		items = append(items, &i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}
